sql:
SELECT COUNT(employee_id) AS sales_manager_count
FROM employee_job_titles
WHERE job_title_id = (SELECT job_title_id FROM job_titles WHERE job_title_name = 'Sales Manager');

external_knowledge:
- "Leaders of the ship's departments" refers to the department heads in the organization;
- "Performance reviews" are assessments conducted to evaluate the performance of employees, including ratings and comments;
- "Latest performance reviews" are the most recent reviews conducted for each department head.

